var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"속보입니다.","JPN":"速報です。","ENG":"This just in.","TWN":"快訊。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 교통 경찰의 검문을 무시하고 도심으로 질주하는 대형 수송차량이 발견되었습니다.","JPN":"現在、警察の検問を無視して都心を疾走する大型輸送車両が発見されています。","ENG":"A large cargo truck has been spotted speeding towards downtown, without stopping at the police checkpoints.","TWN":"有一輛大型貨車無視交警的訊問駛入了市區。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"화면의 이동 예상 동선에 계신 운전자 분은 신속히 이탈하시어......","JPN":"画面の移動予想動線にいる運転中の方は、急ぎ避難して……","ENG":"Any drivers near the expected route shown on the screen is advised to exit the area immediately...","TWN":"處於畫面中的預期移動路線上的駕駛員請馬上離開……"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"속도 줄여, 이유리! 도착하기도 전에 다 죽일 셈이냐!","JPN":"速度を落とせ、カスカベ！　到着する前に皆殺しにするつもりか！","ENG":"Slow down, Yuri! You'll kill us all before we even get there!","TWN":"減速，李悠麗！小心前面的車！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"검문에만 안 걸렸어도 이러진 않았어!","JPN":"検問さえなければ、ここまでしなかったよ！","ENG":"I would if they didn't spot us at the checkpoint!","TWN":"如果不是被訊問，我也不想這樣！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그보다 운전 솜씨는 어때. 면허는 따고도 남겠지?","JPN":"それより私の運転の腕前はどう？　免許も余裕で取れると思わないか？","ENG":"Still, I'm a pretty good driver, right? I can probably get that license now...","TWN":"話說我的駕駛水準怎麼樣，是不是可以拿駕照了？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"넌 절대 차 사지 마라. 사람 잡겠다.","JPN":"お前は絶対に車を買うな。怪我人が出る。","ENG":"You must never drive after this. You'll get someone killed.","TWN":"妳千萬別買車，會出人命的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"걱정해 줘서 고맙네.","JPN":"はいはい、ご心配どうもありがとう。","ENG":"Geez, thanks for the pep talk.","TWN":"謝謝你的關心。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런데 최지훈, 넌 아까부터 왜 아무 말도 없어?","JPN":"ところでゴトウ、さっきから無口だけどどうした？","ENG":"By the way, Jihoon, why are you so quiet?","TWN":"我說崔智勳，你從剛才開始怎麼一直那麼安靜？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"안색도 별로 안 좋아 보이는데......","JPN":"顔色もあまり良くないし……","ENG":"You don't look so good either...","TWN":"臉色看起來也不太好……"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"늑골 말고 어디 다른데도 부러진 거 아냐?","JPN":"肋骨以外もどこか折れてるんじゃない？","ENG":"Did you break something other than your rib?","TWN":"除了肋骨之外，是不是別的部位也斷掉了？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"악담해 줘서 고맙네.","JPN":"ああ、気にしてくれてどうも。","ENG":"Geez, thanks for the pep talk.","TWN":"謝謝你的詛咒。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"쓸데없는 걱정 말고 전방 주시나 잘 하시지.","JPN":"余計な心配しないで、前だけ見てろ。","ENG":"Shut up and just keep your eyes on the front.","TWN":"妳別多管閒事，好好開妳的車。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내 몸 간수도 못 할 만큼 바보는 아니니까.","JPN":"自分の体のことぐらい自分でなんとかする。","ENG":"I'm not so dumb that I can't take care of my own body.","TWN":"我不至於笨到連自己的身體都照顧不好。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야, 왜 그렇게 까칠해?","JPN":"なにさ、なんでそんなにピリピリしてるんだ？","ENG":"Why so grouchy?","TWN":"你怎麼這麼兇？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지훈이 말이 맞다. 지금은 각자 할 일에 집중해야 할 때야.","JPN":"ゴトウの言うとおりだ。今は各自がすべきことに集中する時だ。","ENG":"Jihoon's right. We must focus on each of our roles right now.","TWN":"智勳說得對，先做好自己該做的事情吧。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"최지훈, 저격 지점은 확보했나?","JPN":"ゴトウ、狙撃地点は確保したか？","ENG":"Have you secured the sniping site, Jihoon?","TWN":"崔智勳，選好狙擊地點了嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};